import json as _json

SECTIONS_JSON = [
    {"title": "అవలోకనం", "sub": "Overview", "audio": "ఆంధ్రప్రదేశ్‌లో రవాణా వ్యవస్థ నాలుగు రకాలుగా విభజించబడింది: రోడ్డు రవాణా, రైల్వే రవాణా, జల రవాణా, మరియు వాయు రవాణా. 2022 డిసెంబర్‌ నాటికి నేషనల్ హైవేల (NHs) మినహా రోడ్ల మొత్తం పొడవు 45,321 కిమీ, సర్వే 2024-25 ప్రకారం 45,379 కిమీ. నేషనల్ హైవేల పొడవు 8,163.72 కిమీ, సర్వే ప్రకారం 8,744 కిమీ. సంపూర్ణ రోడ్ నెట్‌వర్క్ 53,484.72 కిమీ. నమోదు వాహనాలు 1.56 కోట్లు, వీటిలో 89.02% నాన్-ట్రాన్స్‌పోర్ట్ వాహనాలు, 10.98% ట్రాన్స్‌పోర్ట్. సర్వే 2024-25: 21.12 లక్షల ట్రాన్స్‌పోర్ట్ వాహనాలు, 1.59 కోట్ల నాన్-ట్రాన్స్‌పోర్ట్ వాహనాలు. మోటార్ వాహన రాజస్వం ₹3,454.56 కోటి. రోడ్ ప్రమాద మరణాలు జనవరి నుండి నవంబర్ 2024 వరకు 7,477. ఆంధ్రప్రదేశ్ స్టేట్ రోడ్ ట్రాన్స్‌పోర్ట్ కార్పొరేషన్ (APSRTC) నేలకు ఈ వ్యవస్థ 4 జోన్‌లు, 12 ప్రాంతాలు, 129 డిపోలుగా సంఘటితం. సర్వే 2024-25: 11,226 బస్సులు (8,475 RTC + 2,751 హైర్డ్), 46,612 ఉద్యోగులు."},
    {"title": "రోడ్డు రవాణా - జాతీయ రహదారులు", "sub": "Road Transport - National Highways", "audio": "ఆంధ్రప్రదేశ్‌లో 52 నేషనల్ హైవేలు ఉన్నాయి, సర్వే 2024-25 ప్రకారం 55 నేషనల్ హైవేలు, మొత్తం పొడవు 8,683.15 కిమీ నుండి ఇప్పుడు 8,744 కిమీ. NH-16 అత్యంత పొడవైన హైవే 1024 కిమీ, NH-326 చిన్నది 13.60 కిమీ. చిత్తూర్, విశాఖపట్నం, నెల్లూరు జిల్లాలలో అధిక సంఖ్యలో నేషనల్ హైవేలు ఉన్నాయి. అనంతపూర్ జిల్లాలో అత్యధిక రోడ్ నెట్‌వర్క్ సాంద్రత. విజయనగరం జిల్లాలో తక్కువ రోడ్ నెట్‌వర్క్. APSRTC ఆదాయం విశాఖపట్నంలో ₹129.88 కోటి (అధిక), విజయనగరంలో ₹100.61 కోటి (తక్కువ). నేషనల్ హైవేల సాంద్రత 50.08 కిమీ/1000 చదరపు కిమీ, జాతీయ సగటు 40.00. ప్రతి లక్ష జనాభాకు 16.53 కిమీ, జాతీయ సగటు 10.89. సర్వే ప్రకారం రోడ్ డెన్సిటీ 17.64 కిమీ/లక్ష జనాభా. 99.09% ఆవాసాలు ప్రధాన మంత్రి గ్రామ సడక్ యోజన (PMGSY) ద్వారా అన్ని-వాతావరణ రోడ్లతో అనుసంధానం."},
    {"title": "రాష్ట్ర రహదారులు", "sub": "State Highways", "audio": "ఆంధ్రప్రదేశ్‌లో 24 రాష్ట్ర రహదారులు (SHs) ఉన్నాయి, మొత్తం పొడవు 12,595.60 కిమీ, సర్వే 2024-25 ప్రకారం 12,653 కిమీ. ఈ హైవేలు బిసిడిఆర్ (BCDR) ప్రమాణాన్ని అనుసరిస్తాయి. ప్రధాన జిల్లా రోడ్ల పొడవు 26,485.51 కిమీ, సర్వే ప్రకారం 26,486 కిమీ. గ్రామీణ రోడ్ల నెట్‌వర్క్ సర్వే 2024-25 ప్రకారం 80,635 కిమీ. నేషనల్ హెచ్‌ఐ (NHAI) నిర్దేశనలో నేషనల్ హైవేల నిర్మాణం: 4,460 కిమీ. ఆంధ్రప్రదేశ్ రోడ్ డెవలప్‌మెంట్ కార్పొరేషన్ (APRDC) పిపిపి ప్రాజెక్టులలో: రెండవ గోదావరి నదీ వంతెన నిర్మాణం ₹808 కోటి, మార్కెట్‌పల్లి-అద్దంకి రోడ్ విస్తరణ ₹1,197 కోటి. నేషనల్ ఇన్‌ఫ్రాస్ట్రక్చర్ ఆనుకూల డెవలప్‌మెంట్ ఎజెన్సీ (NIDA) నిధి: ₹1,158.53 కోటి."},
    {"title": "ఆంధ్రప్రదేశ్ రోడ్డు రవాణా కార్పొరేషన్", "sub": "APSRTC", "audio": "ఆంధ్రప్రదేశ్ స్టేట్ రోడ్ ట్రాన్స్‌పోర్ట్ కార్పొరేషన్ (APSRTC) 4 జోన్‌లుగా సంఘటితం: నెల్లూరు జోన్, కడప జోన్, విజయవాడ జోన్, మరియు విశాఖపట్నం జోన్. APSRTC అత్యధిక టైర్ పనితీరు, ఇంధన సమర్థత, మరియు ఉత్పాదకతలో జాతీయ పురస్కారాలను పొందింది. సర్వే 2024-25 ప్రకారం మొత్తం 11,226 బస్సులు (8,475 APSRTC + 2,751 హైర్డ్), 129 డిపోలు, 46,612 ఉద్యోగులు. నవంబర్ 2024 వరకు రాజస్వం ₹4,261 కోటి. విద్యార్థుల బస్ పాసుల సంఖ్య 8.90 లక్షలు (80% రాయితీ). ఆక్యుపెన్సీ రేటు 69%. ప్రమాద రేటు 0.06 (చాలా తక్కువ, సాధారణ సేఫ్టీ ప్రమాణం)."},
    {"title": "రైల్వే రవాణా", "sub": "Railway Transport", "audio": "ఆంధ్రప్రదేశ్‌లో రైల్వే నెట్‌వర్క్ 3,354 కిమీ పొడవు, 444 రైల్వే స్టేషన్లు ఉన్నాయి. ఆంధ్రప్రదేశ్‌లో మొట్టమొదటి రైల్వే లైన్ 1862లో నిర్మించబడింది, పుత్తూరు నుండి రేణిగుంట (చిత్తూర్ జిల్లా). ప్రస్తుతం 3 రైల్వే జోన్‌లు: దక్షిణ-మధ్య రైల్వే (ఎక్కువ భాగం, ప్రధాన కార్యాలయ సికింద్రాబాద్), దక్షిణ తీర రైల్వే (ప్రధాన కార్యాలయ విశాఖపట్నం, 2019 ఫిబ్రవరి 27 ప్రకటన, 18వ జోన్), దక్షిణ రైల్వే. 4 రైల్వే డివిజన్లు: విజయవాడ, గుంతకల్, గుంటూరు. మొట్టమొదటి డబుల్ డెక్ ఎక్సప్రెస్ రాటిగూడ-గుంటూరు మార్గంలో 2014 మే 13 నుండి. తూర్పు గోదావరి నదీ మీద రాజమండ్రి-కొవ్వూరు రోడ్-రైల్ బ్రిడ్జ్ 2.7 కిమీ పొడవు, ఆంధ్రప్రదేశ్‌లో పొడవైనది. రైల్వే గ్యారేజ్ రీసర్చ్ వర్క్‌షాప్ తిరుపతిలో. వ్యాగన్ వర్క్‌షాప్ గుంటూర్ వద్ద (విజయవాడ సమీపం). విద్యుదీకరణ పూర్తిగా విజయవాడ నుండి తిరుపతి మార్గం."},
    {"title": "మెట్రో రైలు", "sub": "Metro Rail (MRTS)", "audio": "ఆంధ్రప్రదేశ్‌లో 2 మెట్రో రైల్ ట్రాన్జిట్ సిస్టమ్ (MRTS) ప్రాజెక్టులు: విజయవాడ-గుంటూరు-తెనాలి మెట్రో, మొత్తం ఖర్చు ₹6,769 కోటి, AMRC (ఆంధ్ర మెట్రో రైల్ కంపెనీ) చేత నిర్వహణ, MD రామకృష్ణ రెడ్డి. విజయవాడ మెట్రో కారిడార్ 1: పండిట్ నెహ్రూ బస్ స్టేషన్ నుండి పేనమలూరు, 12.76 కిమీ, 12 స్టేషన్లు. కారిడార్ 2: పండిట్ నెహ్రూ నుండి నిడమనూరు, 13.27 కిమీ, 13 స్టేషన్లు. విశాఖపట్నం మెట్రో 4 కారిడార్లు, మొత్తం 42.55 కిమీ: కారిడార్ 1 నాటుకు-కొమ్మాడి 22.8 కిమీ, కారిడార్ 2 గురుద్వారా-ఓల్డ్ పోస్ట్ 5.26 కిమీ, కారిడార్ 3 తాటిచెట్లపాలెం-చిన్న వాల్‌టేర్ 6.91 కిమీ, కారిడార్ 4 నాటుకు-గాజువాక 8.1 కిమీ."},
    {"title": "వందే భారత్ ఎక్స్‌ప్రెస్", "sub": "Vande Bharat Express", "audio": "వందే భారత్ ఎక్సప్రెస్ భారతీయ ఇంటిగ్రల్ కోచ్ ఫ్యాక్టరీ (ICF) చెన్నటిలో నిర్మించబడిన సెమీ-హై స్పీడ్ ట్రేన్, గరిష్ఠ వేగం 180 కిమీ/గంట. 2023 జనవరి 15 నాడు ఆంధ్రప్రదేశ్‌లో సిక్కెందరాబాద్ నుండి విశాఖపట్నం మార్గం సిద్ధం, ప్రధానమంత్రి నరేంద్ర మోదీ చేత ప్రారంభం. ఈ మార్గం వరంగల్, ఖమ్మం, విజయవాడ, రాజమండ్రి, విశాఖపట్నం నగరాల ద్వారా, మొత్తం 699 కిమీ, ప్రయాణ సమయం 8.30 గంటలు. 2023 ఏప్రిల్ 8 నాడు సిక్కెందరాబాద్ నుండి తిరుపతికి రెండవ వందే భారత్ ఎక్సప్రెస్ సిద్ధం."},
    {"title": "జల రవాణా", "sub": "Water Transport", "audio": "జల రవాణా చాలా సస్తైన, ఖరీదైన రవాణా పద్ధతి. ఆంధ్రప్రదేశ్‌లో 1 ప్రధాన ఓడరేవు: విశాఖపట్నం; మరియు 14 నాన్-మేజర్ పోర్ట్‌లు. ఆంధ్రప్రదేశ్ తీరప్రాంతం పాఠ్యపుస్తకం ప్రకారం 972 కిమీ, సర్వే 2024-25 ప్రకారం 1,053.07 కిమీ. విశాఖపట్నం ఓడరేవు దేశంలో అతిపెద్ద సహజంగా ఏర్పడిన ఓడరేవు, 14 బర్థ్‌లు (ప్రస్తుతం 20 బర్థ్‌లకు వ్యవస్థ), 200 హెక్టార్ల జెట్టీ ప్రాంతం. కొలకతా ఓడరేవు నుండి 880 కిమీ, చెన్నై నుండి 780 కిమీ. విశాఖపట్నం ఓడరేవు విజన్ 2030 నాటికి 145 MTPA, 2047 నాటికి 300 MTPA. నీలం ఆర్థికత (బ్లూ ఎకానమీ) 2035 నాటికి $20 బిలియన్ లక్ష్య విలువ."},
    {"title": "నాన్ మేజర్ పోర్ట్‌లు", "sub": "Non-Major Ports", "audio": "ఆంధ్రప్రదేశ్‌లో 17 నాన్-మేజర్ పోర్ట్‌లు. కాకినాడ ఎంకరేజ్ విశాఖపట్నం నుండి 17 కిమీ, హోప్ ఐలాండ్ 145 కిమీ. కాకినాడ డీప్ వాటర్ పోర్ట్ 1999లో ఏర్పాటు, OMC (చమ్మటి మెరిన్ కంపెనీ), సీపోర్ట్‌ల్ Ltd నిర్వహణ. గంగవరం పోర్ట్ విశాఖపట్నం నుండి 15 కిమీ, పర్యావరణ స్నేహపూర్వక, 2009లో సిద్ధం. కృష్ణపట్నం గ్రీనఫీల్డ్ ఫర్స్ట్ పోర్ట్, బీఓఎస్‌టీ (బలిప్లెక్స్‌ ఆయిల్ నెట్‌టర్) నిర్వహణ, నవయుగ్ కంపెనీ సహకారం, 'ఈస్ట్ కోస్ట్‌లో భారతదేశం యొక్క అతిపెద్ద గేట్‌వే', 14 బర్థ్‌లు. దుగ్గరాజుపట్నం శ్రీహరికోట నుండి 23 కిమీ. ఇతర పోర్ట్‌లు: మచిలీపట్నం, నిజాంపట్నం (VANPIC), వొదరేవు, ఘటనాపాడు, రామయ్యపట్నం, కాకినాడ SEZ, భవనాపాడు/మేఘవరం, నక్కపల్లి, భీమునిపట్నం, కళింగపట్నం, రవ్వ, నర్సాపురం. సర్వే 2024-25: కృష్ణపట్నం 37.786 MMT, గంగవరం 16.201 MMT, కాకినాడ డీప్ వాటర్ 11.15 MMT. అభివృద్ధిలో: మచిలీపట్నం ₹5,155.73 కోటి (85 MT), ముళపేట ₹4,361.91 కోటి (23.5 MT), రామయ్యపట్నం ₹9,929.39 కోటి (34.04 MMTPA), కాకినాడ SEZ ₹2,123 కోటి."},
    {"title": "అంతర్గత జలమార్గాలు", "sub": "Internal Waterways", "audio": "ఆంధ్రప్రదేశ్‌లో 4 అంతర్గత జలమార్గాలు: 1) కర్నూలు-కడప కాలువ 119 కిమీ పొడవు, 2) తూర్పుగోదావరి నదీ దానవైపేట నుండి పాసనగలకోట కాలువ, 3) తూర్పుగోదావరి నదీ రాజమండ్రి నుండి ప్రకాశం జిల్లాలోని చీరలకు వెళ్ళే మార్గం, 4) బకింగ్‌హామ్ కాలువ—జాతీయ జలమార్గం-4, కాకినాడ నుండి పాండిచ్చేరి వరకు విస్తరించి ఉంది. ఈ జలమార్గాలు రవాణా, ఇరిగేషన్, ఫిషరీస్ కోసం ఎంతో ముఖ్యమైనవి."},
    {"title": "సాగరమాల ప్రాజెక్ట్", "sub": "Sagarmala Project", "audio": "సాగరమాల భారత కేంద్ర ప్రాజెక్ట్, భారతదేశం తీర రాష్ట్రాలకు 12 రకాల ఓడరేవు ఆధునికీకరణ, తీర ఆర్థిక అభివృద్ధి కోసం. ఆంధ్రప్రదేశ్‌కు సాగరమాల నుండి ₹8,400 కోటి నిధి కేటాయించారు. ఆంధ్రప్రదేశ్‌లో సాగరమాల నిర్మాణం: 1) మచిలీపట్నం ఓడరేవు (కృష్ణ జిల్లా), ₹5,155.73 కోటి ఖర్చు, 85 MT సామర్థ్యం, 2) వొదరేవు ఓడరేవు (ప్రకాశం జిల్లా). ఈ ప్రాజెక్టులు ఓడరేవుల సామర్థ్యం, సెఫ్టీ, పర్యావరణ సంరక్షణ పెంచుతాయి."},
    {"title": "వాయు రవాణా", "sub": "Air Transport", "audio": "ఆంధ్రప్రదేశ్‌లో 6 విమానాశ్రయాలు: 1) విశాఖపట్నం విమానాశ్రయం (అంతర్జాతీయ+దేశీయ, నౌకాదళ స్థావరం, 2 రన్‌వేలు, సర్వే ప్రకారం 2.6 Mppa), 2) విజయవాడ విమానాశ్రయం (AAI నిర్వహణ, గన్నవరం), రెండవ అతిపెద్ద, 3) తిరుపతి విమానాశ్రయం (1976/60 నిర్మాణ సంవత్సరం, రేణిగుంట), మూడవ పురాతన, 4) కడప విమానాశ్రయం (1953లో ఏర్పాటు), 5) రాజమండ్రి విమానాశ్రయం (మధురాపూడి, UDAN స్కీమ్), 6) ఓర్వకల్లు విమానాశ్రయం (సర్వే 2024-25). భోగాపురం అంతర్జాతీయ విమానాశ్రయం నిర్మాణంలో ₹2,302.51 కోటి ఖర్చు, 6 Mppa సామర్థ్యం. గ్రీనఫీల్డ్ విమానాశ్రయ ప్రణాళిక: కుప్పం (చిత్తూర్), దగదర్తి (నెల్లూరు), డోనకొండ (ప్రకాశం), నాగార్జునసాగర్ (గుంటూరు). సర్వే ప్రకారం అదనపు ప్రస్తావిత: శ్రీకాకుళం, తుని, తాడేపల్లిగూడెం. ఆంధ్రప్రదేశ్ వాయు నేవిగేషన్ సర్ভిసెస్ విధానం 2015లో ఆమోదం. భారతదేశం మొత్తంలో వాయు ప్రయాణికులు 1.6 కోట్లు."},
    {"title": "ముఖ్యాంశాలు", "sub": "Key Points", "audio": "ఆంధ్రప్రదేశ్ రవాణా వ్యవస్థ ముఖ్యాంశాలు: నేషనల్ హైవే 52, NH-16 పొడవైనది 1024 కిమీ, చిత్తూర్ జిల్లలో అధిక సంఖ్యలో NHs, విజయనగరం జిల్లలో తక్కువ NHs. APSRTC 4 జోన్‌లు, 129 డిపోలు, సర్వే 2024-25: 11,226 బస్సులు, 46,612 ఉద్యోగులు, ₹4,261 కోటి ఆదాయం. రైల్వే మొట్టమొదటి లైన్ 1862లో, 3,354 కిమీ నెట్‌వర్క్, 444 స్టేషన్లు, 3 జోన్‌లు. దక్షిణ తీర రైల్వే ప్రధాన కార్యాలయ విశాఖపట్నం (18వ జోన్). రైల్వే వర్క్‌షాప్ తిరుపతిలో. విశాఖపట్నం ప్రధాన ఓడరేవు, సహజంగా ఏర్పడినది, 14 బర్థ్‌లు, ₹8,400 కోటి సాగరమాల నిధి. కృష్ణపట్నం గ్రీనఫీల్డ్ ఫర్స్ట్ పోర్ట్. బకింగ్‌హామ్ కాలువ జాతీయ జలమార్గం-4. సర్వే 2024-25: పోస్ట్ ఆఫీసులు 10,672, బ్యాంక్ కార్యాలయాలు 8,388, డిపాజిట్‌లు ₹5,32,801 కోటి, క్రెడిట్ ₹8,61,580 కోటి, క్రెడిట్-డిపాజిట్ రేషియో 161.71%."},
]

