def _seed_ap_geo_ch12_notes_inner(conn, db_exec, row_to_dict, USE_POSTGRES, force=False):
    ph = '%s' if USE_POSTGRES else '?'
    try:
        conn.execute("""CREATE TABLE IF NOT EXISTS study_notes (
            id INTEGER PRIMARY KEY AUTOINCREMENT, subject TEXT NOT NULL DEFAULT 'GK',
            topic TEXT NOT NULL DEFAULT 'AP_Geography', subtopic TEXT DEFAULT '',
            chapter_num INTEGER NOT NULL, chapter_title_te TEXT NOT NULL DEFAULT '',
            chapter_title_en TEXT NOT NULL DEFAULT '', pages_ref TEXT DEFAULT '',
            sections_json TEXT NOT NULL DEFAULT '[]', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )""")
        if USE_POSTGRES: conn.commit()
    except Exception: pass
    cur = db_exec(conn, f"SELECT id FROM study_notes WHERE chapter_num={ph} AND topic={ph}", (12, 'AP_Geography'))
    row = cur.fetchone()
    if row and not force: return {'success': True, 'already_exists': True}
    if row and force: db_exec(conn, f"DELETE FROM study_notes WHERE chapter_num={ph} AND topic={ph}", (12, 'AP_Geography'))
    if USE_POSTGRES: conn.commit()
    db_exec(conn,
        f"INSERT INTO study_notes (subject, topic, subtopic, chapter_num, chapter_title_te, chapter_title_en, pages_ref, sections_json) "
        f"VALUES ({ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph})",
        ('GK', 'AP_Geography', '', 12, 'ఆంధ్రప్రదేశ్‌లో రవాణా', 'Transportation in Andhra Pradesh',
         'pp.94-107', _json.dumps(SECTIONS_JSON, ensure_ascii=False)))
    conn.commit()
    return {'success': True, 'message': 'AP Geo Ch12 notes seeded!'}

def _seed_ap_geo_ch12_mcqs_inner(conn, db_exec, row_to_dict, USE_POSTGRES):
    ph = '%s' if USE_POSTGRES else '?'
    try:
        conn.execute("""CREATE TABLE IF NOT EXISTS mcqs (
            id INTEGER PRIMARY KEY AUTOINCREMENT, subject TEXT NOT NULL DEFAULT 'GK',
            topic TEXT NOT NULL DEFAULT 'AP_Geography', subtopic TEXT DEFAULT '',
            chapter_num INTEGER NOT NULL, section_idx INTEGER DEFAULT 0,
            difficulty INTEGER DEFAULT 1, question TEXT NOT NULL,
            option_a TEXT DEFAULT '', option_b TEXT DEFAULT '',
            option_c TEXT DEFAULT '', option_d TEXT DEFAULT '',
            correct_answer TEXT DEFAULT 'a', explanation TEXT DEFAULT '',
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )""")
        if USE_POSTGRES: conn.commit()
    except Exception: pass
    cur = db_exec(conn, f"SELECT id FROM mcqs WHERE chapter_num={ph} AND topic={ph} LIMIT 1", (12, 'AP_Geography'))
    if cur.fetchone(): return {'success': True, 'already_exists': True}
    for idx, (sec, diff, q, a, b, c, d, ans, exp) in enumerate(MCQ_DATA):
        db_exec(conn,
            f"INSERT INTO mcqs (subject,topic,subtopic,chapter_num,section_idx,difficulty,question,option_a,option_b,option_c,option_d,correct_answer,explanation) "
            f"VALUES ({ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph})",
            ('GK','AP_Geography','',12,sec,diff,q,a,b,c,d,ans,exp))
        if idx % 20 == 0:
            conn.commit()
    conn.commit()
    return {'success': True, 'message': f'AP Geo Ch12: {len(MCQ_DATA)} MCQs seeded!'}
